  1	import React, { FC, useCallback } from 'react';
  2	
  3	import {
  4	  Button,
  5	  ButtonVariant,
  6	  Checkbox,
  7	  Flex,
  8	  FlexItem,
  9	  List,
 10	  ListItem,
 11	  Tooltip,
 12	} from '@patternfly/react-core';
 13	import { LongArrowAltDownIcon, LongArrowAltUpIcon } from '@patternfly/react-icons';
 14	import { NodeNetworkConfigurationInterface, V1beta1NodeNetworkState } from '@types';
 15	import { useNMStateTranslation } from '@utils/hooks/useNMStateTranslation';
 16	import { getPorts } from '@utils/interfaces/getters';
 17	
 18	import useDrawerInterface from '../hooks/useDrawerInterface';
 19	
 20	import './interfaces-popover-body.scss';
 21	
 22	type InterfacesPopoverBodyProps = {
 23	  interfaces: NodeNetworkConfigurationInterface[];
 24	  nodeNetworkState: V1beta1NodeNetworkState;
 25	  hide: () => void;
 26	};
 27	
 28	const Row = ({ children }) => <Flex flexWrap={{ default: 'nowrap' }}>{children}</Flex>;
 29	const FirstColumn = ({ children }) => <FlexItem flex={{ default: 'flex_1' }}>{children}</FlexItem>;
 30	const SecondColumn = ({ children }) => <FlexItem flex={{ default: 'flex_3' }}>{children}</FlexItem>;
 31	
 32	const InterfacesPopoverBody: FC<InterfacesPopoverBodyProps> = ({
 33	  interfaces,
 34	  nodeNetworkState,
 35	  hide,
 36	}) => {
 37	  const { t } = useNMStateTranslation();
 38	  const { setSelectedInterfaceName } = useDrawerInterface();
 39	
 40	  const onInterfaceNameClick = useCallback(
 41	    (iface: NodeNetworkConfigurationInterface) => {
 42	      setSelectedInterfaceName(nodeNetworkState, iface);
 43	      hide();
 44	    },
 45	    [hide],
 46	  );
 47	
 48	  return (
 49	    <List isPlain className="interfaces-popover-body" isBordered>
 50	      {interfaces.map((iface) => {
 51	        const address = iface.ipv4?.address || iface.ipv6?.address;
 52	        const ports = getPorts(iface);
 53	        const Icon = iface.state.toLowerCase() === 'up' ? LongArrowAltUpIcon : LongArrowAltDownIcon;
 54	
 55	        return (
 56	          <ListItem key={iface.name} className="interfaces-popover-body__list-item">
 57	            <Row>
 58	              <FirstColumn>
 59	                <strong>{t('Name')}</strong>
 60	              </FirstColumn>
 61	              <SecondColumn>
 62	                <Button
 63	                  variant={ButtonVariant.link}
 64	                  onClick={() => onInterfaceNameClick(iface)}
 65	                  className="interface-button-name"
 66	                >
 67	                  {iface.name} <Icon color="black" className="pf-u-mr-sm" />
 68	                </Button>
 69	              </SecondColumn>
 70	            </Row>
 71	            <Row>
 72	              <FirstColumn>
 73	                <strong>{t('IP address')}</strong>
 74	              </FirstColumn>
 75	              <SecondColumn>
 76	                {address?.[0] ? (
 77	                  <>
 78	                    {address?.[0]?.ip}/{address?.[0]?.['prefix-length']}
 79	                  </>
 80	                ) : (
 81	                  '-'
 82	                )}
 83	              </SecondColumn>
 84	            </Row>
 85	            <Row>
 86	              <FirstColumn>
 87	                <strong>{t('Ports')}</strong>
 88	              </FirstColumn>
 89	              <SecondColumn>
 90	                {ports?.length ? (
 91	                  <Tooltip
 92	                    content={
 93	                      <List isPlain>
 94	                        {ports.map((port) => (
 95	                          <ListItem key={port}>{port}</ListItem>
 96	                        ))}
 97	                      </List>
 98	                    }
 99	                  >
100	                    <span>{ports.length}</span>
101	                  </Tooltip>
102	                ) : (
103	                  '-'
104	                )}
105	              </SecondColumn>
106	            </Row>
107	            <Row>
108	              <FirstColumn>
109	                <strong>{t('LLDP')}</strong>
110	              </FirstColumn>
111	              <SecondColumn>
112	                <Checkbox
113	                  id={`lldp-enabled-${iface.name}`}
114	                  isDisabled
115	                  isChecked={iface.lldp?.enabled}
116	                />
117	              </SecondColumn>
118	            </Row>
119	
120	            <Row>
121	              <FirstColumn>
122	                <strong>{t('MTU')}</strong>
123	              </FirstColumn>
124	              <SecondColumn>{iface?.mtu || '-'}</SecondColumn>
125	            </Row>
126	          </ListItem>
127	        );
128	      })}
129	    </List>
130	  );
131	};
132	
133	export default InterfacesPopoverBody;

